1	/**
2	 * SyncPlay Desktop - Main Process
3	 *
4	 * Architecture:
5	 * 1. Spawn Node child process for PeerJS signaling server (port 9000)
6	 * 2. Wait for server to be ready, then create BrowserWindow
7	 * 3. Load src/client/index.html via file:// (no Python HTTP server needed)
8	 * 4. On quit, kill the child server process
9	 */
10	
11	const { app, BrowserWindow } = require('electron');
12	const path = require('path');
13	const { spawn } = require('child_process');
14	
15	// ─── Globals ────────────────────────────────────────────────────────────────
16	let serverProcess = null;
17	let mainWindow = null;
18	
19	// ─── Path Resolution ─────────────────────────────────────────────────────────
20	// app.getAppPath() returns:
21	//   dev:   /path/to/syncplay/desktop
22	//   prod:  /path/to/SyncPlay.app/Contents/Resources/app.asar  (FILE)
23	//
24	// In prod, server.js and node_modules/peer are unpacked (asarUnpack) to:
25	//   Resources/app.asar.unpacked/src/server/server.js
26	//   Resources/app.asar.unpacked/node_modules/peer
27	//
28	// We must spawn with cwd=Resources/ (a real dir) and point serverPath at
29	// the unpacked copy so the child Node process can access both the script
30	// and the peer package on the real filesystem.
31	
32	function getAppPaths() {
33	  const appPath = app.getAppPath(); // works in both dev and prod
34	  const appDir  = path.dirname(appPath); // prod → Resources/  dev → desktop/
35	  const isPacked = appPath.endsWith('.asar');
36	
37	  return {
38	    // In prod use the unpacked copy; in dev use the normal path
39	    serverPath: isPacked
40	      ? path.join(appDir, 'app.asar.unpacked', 'src', 'server', 'server.js')
41	      : path.join(appPath, 'src', 'server', 'server.js'),
42	    indexPath:  path.join(appPath, 'src', 'client', 'index.html'),
43	    serverCwd:  appDir,
44	  };
45	}
46	
47	// ─── Server ─────────────────────────────────────────────────────────────────
48	
49	function startServer() {
50	  const { serverPath, serverCwd } = getAppPaths();
51	
52	  console.log(`[SyncPlay] Starting signaling server:`);
53	  console.log(`  serverPath: ${serverPath}`);
54	  console.log(`  serverCwd:  ${serverCwd}`);
55	
56	  serverProcess = spawn('node', [serverPath], {
57	    cwd: serverCwd,
58	    stdio: ['ignore', 'pipe', 'pipe'],
59	    env: { ...process.env, PEER_PORT: '9000' },
60	  });
61	
62	  serverProcess.stdout.on('data', (data) => {
63	    process.stdout.write(`[server] ${data}`);
64	  });
65	
66	  serverProcess.stderr.on('data', (data) => {
67	    process.stderr.write(`[server:err] ${data}`);
68	  });
69	
70	  serverProcess.on('error', (err) => {
71	    console.error('[SyncPlay] Failed to start server:', err.message);
72	  });
73	
74	  serverProcess.on('exit', (code, signal) => {
75	    console.log(`[SyncPlay] Server exited with code=${code} signal=${signal}`);
76	  });
77	}
78	
79	// ─── Window ─────────────────────────────────────────────────────────────────
80	
81	function createWindow() {
82	  const { indexPath } = getAppPaths();
83	
84	  console.log(`[SyncPlay] Loading: file://${indexPath}`);
85	
86	  mainWindow = new BrowserWindow({
87	    width: 1100,
88	    height: 750,
89	    title: 'SyncPlay',
90	    webPreferences: {
91	      preload: path.join(__dirname, 'preload.js'),
92	      contextIsolation: true,
93	      nodeIntegration: false,
94	    },
95	  });
96	
97	  mainWindow.loadFile(indexPath).catch((err) => {
98	    console.error('[SyncPlay] Failed to load index.html:', err.message);
99	  });
100	
101	  mainWindow.on('closed', () => {
102	    mainWindow = null;
103	  });
104	
105	  // Log console errors from renderer (error level only)
106	  mainWindow.webContents.on('console-message', (event, level, message) => {
107	    if (level >= 2) {
108	      console.error(`[renderer:error] ${message}`);
109	    }
110	  });
111	
112	  mainWindow.webContents.on('render-process-gone', (event, details) => {
113	    console.error('[SyncPlay] Renderer process gone:', details.reason);
